14	/**
15	 * Count files that still exist on disk from manifest lists.
16	 */
17	async function countExistingFiles(projectDir, manifest) {
18	  const allFiles = [
19	    ...(manifest.files.skf || []),
20	    ...(manifest.files.sidecar || []),
21	    ...(manifest.files.ide_skills || []),
22	    ...(manifest.files.learning || []),
23	    ...(manifest.files.output || []),
24	  ];
25	
26	  let existing = 0;
27	  for (const file of allFiles) {
28	    if (await fs.pathExists(path.join(projectDir, file))) {
29	      existing++;
30	    }
31	  }
32	  return { total: allFiles.length, existing };
33	}
34	
35	/**
36	 * Display what will be removed, grouped by category.
37	 */
38	async function displayRemovalPlan(projectDir, manifest) {
39	  const categories = [
40	    { key: 'skf', label: 'SKF module files', dir: manifest.skf_folder },
41	    { key: 'sidecar', label: 'Agent sidecar state', dir: '_bmad/_memory/forger-sidecar' },
42	    { key: 'ide_skills', label: 'IDE skill directories' },
43	    { key: 'learning', label: 'Learning material', dir: '_skf-learn' },
44	    { key: 'output', label: 'Output folder scaffolding' },
45	  ];
46	
47	  const lines = [];
48	  for (const cat of categories) {
49	    const files = manifest.files[cat.key] || [];
50	    if (files.length === 0) continue;
51	
52	    // Count how many still exist
53	    let existCount = 0;
54	    for (const f of files) {
55	      if (await fs.pathExists(path.join(projectDir, f))) existCount++;
56	    }
57	
58	    if (existCount === 0) continue;
59	
60	    if (cat.dir) {
61	      lines.push(`${chalk.red('×')} ${cat.label} ${chalk.dim(`(${cat.dir}/ — ${existCount} files)`)}`);
62	    } else {
63	      lines.push(`${chalk.red('×')} ${cat.label} ${chalk.dim(`(${existCount} files)`)}`);
64	    }
65	  }
66	
67	  // Manifest itself
68	  lines.push(`${chalk.red('×')} Installation manifest ${chalk.dim(`(${MANIFEST_DIR}/${MANIFEST_FILE})`)}`);
69	
70	  log.warn(`The following will be removed:\n${lines.join('\n')}`);
71	}
72	
73	/**
74	 * Remove files listed in the manifest, then clean empty parent directories.
75	 */
76	async function removeFiles(projectDir, fileList) {
77	  let removed = 0;
78	  for (const file of fileList) {
79	    const fullPath = path.join(projectDir, file);
80	    if (await fs.pathExists(fullPath)) {
81	      await fs.remove(fullPath);
82	      removed++;
83	    }
84	  }
85	  return removed;
86	}
87	
88	/**
89	 * Remove a directory if it exists and is empty (or force remove).
90	 */
91	async function removeEmptyDir(dirPath) {
92	  if (!(await fs.pathExists(dirPath))) return;
93	  try {
94	    const entries = await fs.readdir(dirPath);
95	    if (entries.length === 0) {
96	      await fs.remove(dirPath);
97	    }
98	  } catch {
99	    // ignore
100	  }
101	}
102	
103	module.exports = {
104	  command: 'uninstall',
105	  description: 'Remove SKF installation from the current project',
106	  options: [],
107	  action: async () => {
108	    try {
109	      const projectDir = process.cwd();
110	      const manifest = await readManifest(projectDir);
111	
112	      if (!manifest) {
113	        // Check if SKF exists without manifest
114	        const skfExists = await fs.pathExists(path.join(projectDir, '_bmad/skf'));
115	        if (skfExists) {
116	          log.warn(
117	            'No manifest found. Reinstall first to generate one,\nthen run uninstall again for clean removal.\nRun: npx bmad-module-skill-forge install',
118	          );
119	        } else {
120	          log.warn('SKF is not installed in this directory.');
121	        }
122	        process.exit(0);
123	        return;
124	      }
125	
126	      const { existing } = await countExistingFiles(projectDir, manifest);
127	      if (existing === 0) {
